    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-2026-001)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchByTracking" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searchedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5 class="mb-0">Shipment @searchedShipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @searchedShipment.Origin</p>
                    <p><strong>To:</strong> @searchedShipment.Destination</p>
                    <p><strong>Description:</strong> @searchedShipment.Description</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(searchedShipment.Status) fs-6">@searchedShipment.Status</span></p>
                    <p><strong>Shipped:</strong> @searchedShipment.ShippedDate.ToString("MMMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @searchedShipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</p>
                    @if (searchedShipment.ActualDelivery.HasValue)
                    {
                        <p><strong>Delivered:</strong> @searchedShipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</p>
                    }
                </div>
            </div>
            @{ RenderStatusTimeline(searchedShipment); }
        </div>
    </div>
}
else if (searchPerformed && !searching)
{
    <div class="alert alert-warning">No shipment found with tracking number "<strong>@lastSearchedNumber</strong>".</div>
}

<hr class="my-4" />

<h2>My Shipments</h2>

@if (loadingMyShipments)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments?.Any() == true)
{
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h6 class="card-title">
                            <code>@shipment.TrackingNumber</code>
                            <span class="badge @GetStatusBadgeClass(shipment.Status) ms-2">@shipment.Status</span>
                        </h6>
                        <p class="card-text mb-1">@shipment.Origin → @shipment.Destination</p>
                        <p class="card-text mb-1"><small class="text-muted">@shipment.Description</small></p>
                        <p class="card-text">
                            <small><strong>ETA:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</small>
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted">No shipments found for your account.</p>
}

@code {
